static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template & /* tmpl */,
        const autoparser::generation_params & inputs) {
    common_chat_params data;

    // Build prompt following Mistral Instruct v0.3 format:
    //   https://huggingface.co/mistralai/Mistral-7B-Instruct-v0.3
    // System message is prepended (with a blank line) to the first user turn.
    // Each user turn is wrapped with [INST] / [/INST].
    // Each assistant turn is terminated with </s>.
    std::string prompt;
    bool        is_inside_turn = false;
    std::string pending_system;

    for (const auto & msg : inputs.messages) {
        const auto role    = msg.value("role", "");
        const auto content = msg.value("content", "");

        if (role == "system") {
            pending_system = content;
        } else if (role == "user") {
            if (!is_inside_turn) {
                prompt        += "[INST] ";
                is_inside_turn = true;
            }
            if (!pending_system.empty()) {
                prompt += pending_system + "\n\n";
                pending_system.clear();
            }
            prompt += content + " [/INST]";
        } else {
            // assistant
            prompt        += " " + content + "</s>";
            is_inside_turn = false;
        }
    }

    if (inputs.add_generation_prompt) {
        prompt += inputs.generation_prompt;
    }

    data.prompt = prompt;
    data.format = COMMON_CHAT_FORMAT_PEG_NATIVE;

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto end = p.end();
        return p.prefix(inputs.generation_prompt) + p.content(p.rest()) + end;
    });
    data.parser = parser.save();

    return data;
}

